SELECT UTLINSTT_ID ,FUND_ID ,FUND_NM ,FUND_PTRN ,ORGZ_TRGPFT ,AUDIT_STG ,TO_TIMESTAMP(WODY) as wody ,FUND_DSNC ,TO_TIMESTAMP(RGSN_TS) as rgsnTs ,RGSN_USER_ID ,TO_TIMESTAMP(AMNN_TS) as amnnTs ,AMNN_USER_ID FROM TB_BOX_IVT_PRDT_FUND_INFO_M WHERE UTLINSTT_ID = #{utlinsttId}
AND FUND_NM LIKE '%' || #{searchFundName} || '%'
ORDER BY RGSN_TS DESC

