    	 UPDATE TB_BOX_IVT_PRDT_FUND_INFO_M
	        SET
    			FUND_NM 					= #{fundNm}
				,FUND_PTRN                  = #{fundPtrn}
				,ORGZ_TRGPFT                = #{orgzTrgpft}
				,IBK_INVSTMNT_PRPL_AMT      = #{ibkInvstmntPrplAmt}
				,STDR_ERN_RT                = #{stdrErnRt}
				,CNTNNC_PDYY                = #{cntnncPdyy}
				,RSLT_MENDNG_IRR_EXCESS_ERN = #{rsltMendngIrrExcessErn}
				,INVT_PDYY                  = #{invtPdyy}
				,MNG_MENDNG_RT              = #{mngMendngRt}
				,PMNT_MTHD                  = #{pmntMthd}
				
					
						,INVT_TGT           = #{invtTgt}
					
					
						,INVT_TGT           = DEFAULT
					
				
				
					
						,ORGZ_TGPR      = #{orgzTgpr}
					
					
						,ORGZ_TGPR      = DEFAULT
					
				
				
					
						,ORGZ_RTO       = #{orgzRto}
					
					
						,ORGZ_RTO       = DEFAULT
					
				
				
					,IBK_PRPL_AMT = #{ibkPrplAmt}
				
				
					,IBK_PRPL_RTO = #{ibkPrplRto}
				
				,AMNN_TS				= CURRENT_TIMESTAMP
				,AMNN_USER_ID   		= #{amnnUserId}
				
 				,GP_FNCNINFO			= #{gpFncnInfo}
 				
 				
				,FUND_DSNC				= #{fundDsnc}
				
				
				,PROPOSAL_DOC_BASE_DAY  = #{ProposalDocBaseDay}
				
	        WHERE
	      		FUND_ID					= #{fundId}
	        	AND UTLINSTT_ID 		= #{utlinsttId}

    	 UPDATE
    	 	TB_BOX_IVT_FNCN_ENLS_PSST_R
	        SET
	        	INVST_INST          = #{invstInst}
				,INVSTMNY           = #{invstMny}
				,RATE				= #{rate}
				,PROGRS_STG			= #{progrsStg}
	        	,AMNN_TS			= CURRENT_TIMESTAMP
				,AMNN_USER_ID   	= #{amnnUserId}
	        WHERE
	        	FUND_ID = #{fundId}
	        	AND SQN = #{sqn}

    	UPDATE
    		 TB_BOX_IVT_PRMR_LP_CHC_FILD_R
    		 SET
		        INVST_INST          = #{invstInst}
				,SPRN_FILD          = #{sprnFild}
				,SPRN_AMT  			= #{sprnAmt}
				,PROGRS_STG			= #{progrsStg}
	        	,AMNN_TS			= CURRENT_TIMESTAMP
				,AMNN_USER_ID   	= #{amnnUserId}
	        WHERE
	        	FUND_ID = #{fundId}
	        	AND SQN = #{sqn}

