				,FUND_OPR_TS                = #{fundOprTs}
				,CPTS_TTSM                  = #{cptsTtsm}
				,PAY_CAPL                   = #{payCapl}
				
					
						,DSCPL_YN           = #{dscplYn}
					
					
						,DSCPL_YN           = DEFAULT
					
				
				
					
						,OPRATN_SCALE_CO    = #{opratnScaleCo}
					
					
						,OPRATN_SCALE_CO    = DEFAULT
					
				
				
					
