						,BLIND_AM    		= #{blindAm}
					
					
						,BLIND_AM           = DEFAULT
					
				
				
					
						,PRJCT_CO           = #{prjctCo}
					
					
						,PRJCT_CO           = DEFAULT
					
				
 				
					
						,PRJCT_AM           = #{prjctAm}
					
					
						,PRJCT_AM           = DEFAULT
					
				
				
					
						,LQD_FUND_ERNRT     = #{lqdFundErnrt}
					
					
						,LQD_FUND_ERNRT     = DEFAULT
					
				
				,AST_TTSM_AMT               = #{astTtsmAmt}
				,LBLT_CPST_AMT              = #{lbltCpstAmt}
				,CPTS_TTSM_AMT              = #{cptsTtsmAmt}
				,BSN_ERN                    = #{bsnErn}
				,BSN_CT                     = #{bsnCt}
				,CTNP_AMT                   = #{ctnpAmt}
				,AST_TTSM_AMT_1Y            = #{astTtsmAmt1y}
				,AST_TTSM_AMT_2Y            = #{astTtsmAmt2y}
				,LBLT_CPST_AMT_1Y           = #{lbltCpstAmt1y}
				,LBLT_CPST_AMT_2Y           = #{lbltCpstAmt2y}
				,CPTS_TTSM_AMT_1Y           = #{cptsTtsmAmt1y}
				,CPTS_TTSM_AMT_2Y           = #{cptsTtsmAmt2y}
				,BSN_ERN_1Y                 = #{bsnErn1y}
				,BSN_ERN_2Y                 = #{bsnErn2y}
				,BSN_CT_1Y                  = #{bsnCt1y}
				,BSN_CT_2Y                  = #{bsnCt2y}
