				,OPRATN_HNF_INFO_TOT_CO     = #{opratnHnfInfoTotCo}
				,OPRATN_HNF_INFO_MNGR_NM    = #{opratnHnfInfoMngrNm}
				
					
						,OPRATN_HNF_INFO_DSCPL_YN   = #{opratnHnfInfoDscplYn}
					
					
