				,MANAGEDTA_ATCHMNFL			= #{managedtaAtchmnfl}
				
				,AMNN_TS					= CURRENT_TIMESTAMP
				,AMNN_USER_ID   			= #{amnnUserId}
				
				, COGP_YN					= #{cogpYn}
				
				
				, MAJOR_PRN_NM        	    = #{majorPrnNm}
				
	        WHERE
