	        	AND UTLINSTT_ID = #{utlinsttId}

    	UPDATE TB_BOX_IVT_OPRATN_HNF_MNTNC_RT_R
	        SET
				OPRATN_HNF_NM	= #{opratnHnfNm}
				,NOW_HFFC_YN	= #{nowHffcYn}
				,RM				= #{rm}
				,AMNN_TS		= CURRENT_TIMESTAMP
				,AMNN_USER_ID   = #{amnnUserId}
		    WHERE
		    	SQN = #{sqn} AND
		    	FUND_ID = #{fundId}

    	UPDATE TB_BOX_IVT_PROPSE_FUND_PARTCPTN_R
	        SET
	      		PARTCPTN_NM				= #{partcptnNm}
				,HMRS_DSNC				= #{hmrsDsnc}
				,INVT_CAREER			= #{invtCareer}
				,CNWK_YY_CNT			= #{cnwkYyCnt}
