				,TEN_FYER_INVM_RTRVLACRS_INVT	= #{tenFyerInvmRtrvlacrsInvt}
				,TEN_FYER_INVM_RTRVLACRS_RTRVL	= #{tenFyerInvmRtrvlacrsRtrvl}
				,AMNN_TS				= CURRENT_TIMESTAMP
				,AMNN_USER_ID   		= #{amnnUserId}
		    WHERE
		    	SQN = #{sqn} AND
		    	FUND_ID = #{fundId}

    	UPDATE TB_BOX_IVT_OPRATN_HNF_INFO_DSCPL_L
	        SET
	      		NAME			= #{name}
	      		,RMDP			= #{rmdp}
	      		,RMRK			= #{rmrk}
	      		,AMNN_TS		= CURRENT_TIMESTAMP
				,AMNN_USER_ID   = #{amnnUserId}
		    WHERE
		    	SQN = #{sqn}
    			AND FUND_ID = #{fundId}

UPDATE TB_BOX_IVT_FUND_STCH_CNFG_L
SET
	STCH_NM			= #{stchNm}
	,PRTN_AMT		= #{prtnAmt}
	,PRTN_RTO		= #{prtnRto}
	,RMRK			= #{rmrk}
	,AMNN_TS		= CURRENT_TIMESTAMP
	,AMNN_USER_ID   = #{amnnUserId}
WHERE
	RGSN_SQN = #{rgsnSqn}
	AND FUND_ID = #{fundId}
